/* wms-master-account-sql-oracle.xml - insertInterfaceAccount */
INSERT INTO TWORK_INTF_AC_RCV (
	   CTKEY			/* 센터코드 */
	 , ACKEY			/* 거래처코드 */
	 , ACNM				/* 거래처명 */
	 , ACTYPECD			/* 거래처구분 */
	 , OPERSTATYPE		/* 거래처상태 */
	 , ADDRESS1			/* 주소1 */
	 , ADDRESS2			/* 주소2 */
	 , TEL1				/* 전화번호1 */
	 , CONTACT			/* 담당자 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{ackey}
	 , #{acname}
	 , #{actype}
	 , #{acstatus}
	 , #{address1}
	 , #{address2}
	 , #{tel1}
	 , #{contact}
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-account-sql-oracle.xml - insertTworkMstAc */
INSERT INTO TWORK_MST_AC (
	   CTKEY				/* 센터 코드 */
	 , ACKEY				/* 거래처 코드 */
	 , ACNM					/* 거래처 명 */
	 , ACTYPECD				/* 거래처 구분 */
	 , OPERSTATYPE			/* 운영 상태 구분 */
	 , ADDRESS1				/* 주소1 */
	 , ADDRESS2				/* 주소2 */
	 , TEL1					/* 전화 번호 1 */
	 , CONTACT				/* 담당자 */
	 , INSERTDATE			/* 입력 일시 */
	 , INSERTURKEY			/* 입력 사용자 ID */
	 , UPDATEDATE			/* 수정 일시 */
	 , UPDATEURKEY			/* 수정 사용자 ID */
	 )
VALUES (
	   #{ctkey}
	 , #{ackey}
	 , #{acname}
	 , #{actype}
	 , #{acstatus}
	 , #{address1}
	 , #{address2}
	 , #{tel1}
	 , #{contact}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )
